contract WadzPayToken is Context, IERC20, IERC20Metadata, Ownable {
    using SafeMath for uint256;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;

    uint256 private _totalSupply;
    string private _name;
    string private _symbol;


    mapping(address => bool) public blackList;
    mapping(address => uint256) private lastTxTimestamp;
    bool private antibotPaused = true;

    struct WhitelistRound {
        uint256 duration;
        uint256 amountMax;
        mapping(address => bool) addresses;
        mapping(address => uint256) purchased;
    }

    WhitelistRound[] public _tgeWhitelistRounds;

    uint256 public _tgeTimestamp;
    address public _tgePairAddress;

    uint256 private maxTxPercent = 1000;
    uint256 private transferDelay = 0;


    constructor() {
        _name = "WadzPay Token";
        _symbol = "WTK";
        _mint(msg.sender, 250000000 * (10**uint256(decimals())));
    }


    function name() public view virtual override returns (string memory) {
        return _name;
    }


    function symbol() public view virtual override returns (string memory) {
        return _symbol;
    }


    function decimals() public view virtual override returns (uint8) {
        return 18;
    }


    function totalSupply() public view virtual override returns (uint256) {
        return _totalSupply;
    }


    function balanceOf(address account)
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _balances[account];
    }


    function transfer(address recipient, uint256 amount)
        public
        virtual
        override
        returns (bool)
    {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }


    function allowance(address owner, address spender)
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _allowances[owner][spender];
    }


    function approve(address spender, uint256 amount)
        public
        virtual
        override
        returns (bool)
    {
        _approve(_msgSender(), spender, amount);
        return true;
    }


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public virtual override returns (bool) {
        _transfer(sender, recipient, amount);

        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(
            currentAllowance >= amount,
            "ERC20: transfer amount exceeds allowance"
        );
        _approve(sender, _msgSender(), currentAllowance - amount);

        return true;
    }


    function increaseAllowance(address spender, uint256 addedValue)
        public
        virtual
        returns (bool)
    {
        _approve(
            _msgSender(),
            spender,
            _allowances[_msgSender()][spender] + addedValue
        );
        return true;
    }


    function decreaseAllowance(address spender, uint256 subtractedValue)
        public
        virtual
        returns (bool)
    {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(
            currentAllowance >= subtractedValue,
            "ERC20: decreased allowance below zero"
        );
        _approve(_msgSender(), spender, currentAllowance - subtractedValue);

        return true;
    }

    function mint(address account, uint256 amount) public onlyOwner {
        _mint(account, amount * (10**uint256(decimals())));
    }

    function destroy(address account, uint256 amount) public onlyOwner {
        _burn(account, amount * (10**uint256(decimals())));
    }


    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");
        if (!antibotPaused) {
            if (sender != owner() && recipient != owner()) {
                require(
                    amount <= (totalSupply() * maxTxPercent) / 1000,
                    "Overflow max transfer amount"
                );
            }
            require(!blackList[sender], "Blacklisted seller");
            _applyTGEWhitelist(sender, recipient, amount);
            lastTxTimestamp[recipient] = block.timestamp;
        }

        _beforeTokenTransfer(sender, recipient, amount);

        uint256 senderBalance = _balances[sender];
        require(
            senderBalance >= amount,
            "ERC20: transfer amount exceeds balance"
        );
        _balances[sender] = senderBalance - amount;
        _balances[recipient] += amount;

        emit Transfer(sender, recipient, amount);
    }


    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: mint to the zero address");

        _beforeTokenTransfer(address(0), account, amount);

        _totalSupply += amount;
        _balances[account] += amount;
        emit Transfer(address(0), account, amount);
    }


    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: burn from the zero address");

        _beforeTokenTransfer(account, address(0), amount);

        uint256 accountBalance = _balances[account];
        require(accountBalance >= amount, "ERC20: burn amount exceeds balance");
        _balances[account] = accountBalance - amount;
        _totalSupply -= amount;

        emit Transfer(account, address(0), amount);
    }


    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }


    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}





    function addBlacklist(address _bot) external onlyOwner {
        blackList[_bot] = true;
        emit AddedBlackList(_bot);
    }


    function removeBlacklist(address _addr) external onlyOwner {
        blackList[_addr] = false;
        emit RemovedBlackList(_addr);
    }


    function destroyBlackFunds(address _blackListedUser) external onlyOwner {
        require(blackList[_blackListedUser], "This user is not a member of blacklist");
        uint dirtyFunds = balanceOf(_blackListedUser);
        _balances[_blackListedUser] = 0;
        _totalSupply -= dirtyFunds;
        emit DestroyedBlackFunds(_blackListedUser, dirtyFunds);
    }

    event DestroyedBlackFunds(address _blackListedUser, uint _balance);

    event AddedBlackList(address _user);

    event RemovedBlackList(address _user);




    function createTGEWhitelist(address pairAddress, uint256[] calldata durations, uint256[] calldata amountsMax) external onlyOwner {
        require(durations.length == amountsMax.length, "Invalid whitelist(s)");

        _tgePairAddress = pairAddress;

        if(durations.length > 0) {

            delete _tgeWhitelistRounds;

            for (uint256 i = 0; i < durations.length; i++) {
                WhitelistRound storage wlRound = _tgeWhitelistRounds[i];
                wlRound.duration = durations[i];
                wlRound.amountMax = amountsMax[i];
            }

        }
    }



    function modifyTGEWhitelist(uint256 index, uint256 duration, uint256 amountMax, address[] calldata addresses, bool enabled) external onlyOwner {
        require(index < _tgeWhitelistRounds.length, "Invalid index");
        require(amountMax > 0, "Invalid amountMax");

        if(duration != _tgeWhitelistRounds[index].duration)
            _tgeWhitelistRounds[index].duration = duration;

        if(amountMax != _tgeWhitelistRounds[index].amountMax)
            _tgeWhitelistRounds[index].amountMax = amountMax;

        for (uint256 i = 0; i < addresses.length; i++) {
            _tgeWhitelistRounds[index].addresses[addresses[i]] = enabled;
        }
    }



    function getTGEWhitelistRound() public view returns (uint256, uint256, uint256, uint256, bool, uint256) {

        if(_tgeTimestamp > 0) {

            uint256 wlCloseTimestampLast = _tgeTimestamp;

            for (uint256 i = 0; i < _tgeWhitelistRounds.length; i++) {

                WhitelistRound storage wlRound = _tgeWhitelistRounds[i];

                wlCloseTimestampLast = wlCloseTimestampLast.add(wlRound.duration);
                if(block.timestamp <= wlCloseTimestampLast)
                    return (i.add(1), wlRound.duration, wlCloseTimestampLast, wlRound.amountMax, wlRound.addresses[_msgSender()], wlRound.purchased[_msgSender()]);
            }

        }

        return (0, 0, 0, 0, false, 0);
    }



    function _applyTGEWhitelist(address sender, address recipient, uint256 amount) internal {

        if(_tgePairAddress == address(0) || _tgeWhitelistRounds.length == 0)
            return;

        if(_tgeTimestamp == 0 && sender != _tgePairAddress && recipient == _tgePairAddress && amount > 0)
            _tgeTimestamp = block.timestamp;

        if(sender == _tgePairAddress && recipient != _tgePairAddress) {


            (uint256 wlRoundNumber,,,,,) = getTGEWhitelistRound();

            if(wlRoundNumber > 0) {

                WhitelistRound storage wlRound = _tgeWhitelistRounds[wlRoundNumber.sub(1)];

                require(wlRound.addresses[recipient], "TGE - Buyer is not whitelisted");

                uint256 amountRemaining = 0;

                if(wlRound.purchased[recipient] < wlRound.amountMax)
                    amountRemaining = wlRound.amountMax.sub(wlRound.purchased[recipient]);

                require(amount <= amountRemaining, "TGE - Amount exceeds whitelist maximum");
                wlRound.purchased[recipient] = wlRound.purchased[recipient].add(amount);

            }

        }

    }



    function setMaxTxPercent(uint256 _maxTxPercent) external onlyOwner {
        maxTxPercent = _maxTxPercent;
    }


    function setTransferDelay(uint256 _transferDelay) external onlyOwner {
        transferDelay = _transferDelay;
    }


    function setAntibotPaused(bool _antibotPaused) external onlyOwner {
        antibotPaused = _antibotPaused;
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import './utils/Counters.sol';
import "./interfaces/IPancakeRouter02.sol";
import "./interfaces/IWBNB.sol";
import './tokens/LuckyToken.sol';

contract RevenueSharingPool is Ownable {

    using SafeERC20 for IERC20;
    using Counters for Counters.Counter;
    Counters.Counter private _roundId;


    IERC20 public luckyBusd;
    IERC20 public lucky;
    IERC20 public BUSD;
    IWBNB public wNative;
    IPancakeRouter02 public exchangeRouter;


    uint256 MAX_NUMBER;
    uint256 public START_ROUND_DATE;
    uint256 public MAX_DATE = 7;


    mapping(uint256 => mapping(uint256 => uint256)) public totalStake;
    mapping(uint256 => uint256) public totalLuckyRevenue;
    mapping(uint256 => mapping(uint256 => mapping(address => uint256))) stakeAmount; 

    mapping(address => bool) public whitelists;


    struct UserInfo {
        uint256 amount;
        uint256 rewardDept;
        uint256 pendingReward;
        uint256 lastUpdateRoundId;
    }

    mapping(address => UserInfo) public userInfo;


    struct PoolInfo {
	    uint256 winRate;
	    uint256 TPV;
	    uint256 buyBack;
	    uint256 TVL;
    }

    mapping(uint256 => PoolInfo) public poolInfo; 

    event DepositStake(address indexed account, uint256 amount, uint256 timestamp);
    event WithdrawStake(address indexed account, uint256 amount, uint256 timestamp);
    event ClaimReward(address indexed account, uint256 amount, uint256 timestamp);
    event DistributeLuckyRevenue(address from, address to, uint256 amounts);

    struct InputToken {
        address token;
        uint256 amount;
        address[] tokenToBUSDPath;
    }

    modifier isWhitelisted(address addr) {
        require(whitelists[addr], "Permission Denied");
        _;
    }

    constructor (
        address _lucky,
        address _luckyBusd,
        address owner_,
        IPancakeRouter02 _exchangeRouter,
        address _busd,
        address _wNative
    ) public {
        exchangeRouter = IPancakeRouter02(_exchangeRouter);
        luckyBusd = IERC20(_luckyBusd);
        lucky = IERC20(_lucky);
        wNative = IWBNB(_wNative);
        BUSD = IERC20(_busd);
        MAX_NUMBER = 0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff;
        START_ROUND_DATE = block.timestamp;        
        transferOwnership(owner_);
    }


    receive() external payable {}




    function depositToken(uint256 amount) external {
        UserInfo storage user = userInfo[msg.sender];
        require(amount > 0, "Insufficient deposit amount!");
        luckyBusd.safeTransferFrom(msg.sender, address(this), amount);
        uint256 depositDate = getDepositDate();
        uint256 roundId = getCurrentRoundId();

        if (!isStakeUpToDate(roundId)) {
           updatePendingStake(); 
        }

        user.amount += amount;
        updateStake(roundId, depositDate, amount);
        emit DepositStake(msg.sender, amount, block.timestamp);
    }


    function withdrawToken() external {
        UserInfo storage user = userInfo[msg.sender];
        uint256 roundId = getCurrentRoundId();

        if (!isStakeUpToDate(roundId)) {
           updatePendingStake(); 
        }

        updatePendingReward();
        uint256 amount = user.amount;
        user.amount = 0;
        removeStake(roundId);
        luckyBusd.safeTransfer(msg.sender, amount);
        emit WithdrawStake(msg.sender, amount, block.timestamp);
    }


    function claimReward() external {
        UserInfo storage user = userInfo[msg.sender];
        uint256 roundId = getCurrentRoundId();

        if (user.amount > 0) {
            if (!isStakeUpToDate(roundId)) {
               updatePendingStake(); 
            }
            updatePendingReward();
        }

        uint256 claimableLuckyReward = user.pendingReward;
        require(claimableLuckyReward > 0, "Not enough claimable LUCKY reward!");
        user.rewardDept += claimableLuckyReward;
        user.pendingReward -= claimableLuckyReward;
        lucky.safeTransfer(msg.sender, claimableLuckyReward);
        emit ClaimReward(msg.sender, claimableLuckyReward, block.timestamp);
    }



    function updateRoundId() internal {
        _roundId.increment(); 
    }


    function updateMaxDate(uint256 newMaxDate) external onlyOwner {
        MAX_DATE = newMaxDate;
    }

    function addWhitelist(address addr) external onlyOwner {
        whitelists[addr] = true;
    }

    function removeWhitelist(address addr) external onlyOwner {
        whitelists[addr] = false;
    }

    function updatePoolInfo(uint256 winRate, uint256 TPV, uint256 buyBack, uint256 roundID) internal {
	    uint256 totalValueLock = luckyBusd.balanceOf(address(this));
	    PoolInfo storage _poolInfo = poolInfo[roundID];
	    _poolInfo.winRate = winRate;
	    _poolInfo.TPV = TPV;
            _poolInfo.buyBack = buyBack;
	    _poolInfo.TVL = totalValueLock;
    }

    function removeStake(uint256 roundId) internal {
        for (uint256 i = 1; i <= MAX_DATE; i++) {
            uint256 amount = stakeAmount[roundId][i][msg.sender];
            stakeAmount[roundId][i][msg.sender] -= amount;
            totalStake[roundId][i] -= amount;
        }
    }

    function updateStake(uint256 roundId, uint256 depositDate, uint256 amount) internal {
        for(uint256 i = depositDate; i <= MAX_DATE; i++) {
            stakeAmount[roundId][i][msg.sender] += amount;
            totalStake[roundId][i] += amount;
        }
    }


    function updatePendingStake() internal {
        UserInfo storage user = userInfo[msg.sender];
        uint256 lastUpdateRoundId = user.lastUpdateRoundId;
        uint256 currentRoundId = getCurrentRoundId();
        uint256 amount = user.amount;

        for(uint256 i = (lastUpdateRoundId + 1); i <= currentRoundId; i++) {
            for(uint256 j = 1; j <= MAX_DATE; j++) {
                stakeAmount[i][j][msg.sender] = amount;
            }
        }
        user.lastUpdateRoundId = currentRoundId;
    }

    function updateTotalStake(uint256 roundId) internal {
        uint256 _totalStake = luckyBusd.balanceOf(address(this));
        for(uint256 i = 1; i <= MAX_DATE; i++) {
            totalStake[roundId][i] = _totalStake;
        }
    }

    function updatePendingReward() internal {
        UserInfo storage user = userInfo[msg.sender];
        uint256 luckyReward = calculateTotalLuckyReward();
        uint256 luckyRewardDept = user.rewardDept;
        user.pendingReward = (luckyReward - luckyRewardDept);
    }

    function calculateLuckyReward(address account, uint256 roundId) internal view returns (uint256) {
        uint256 luckyReward;
        uint256 totalLuckyRevenuePerDay = getTotalLuckyRewardPerDay(roundId);
        if (totalLuckyRevenuePerDay == 0) {
            return 0;
        }
        for (uint256 i = 1; i <= MAX_DATE; i++) {
            uint256 amount = stakeAmount[roundId][i][account];
            if (amount == 0) continue;
            uint256 _totalStake = totalStake[roundId][i];
            uint256 userSharesPerDay = (amount * 1e18) / _totalStake;
            luckyReward += (totalLuckyRevenuePerDay * userSharesPerDay) / 1e18;
        }
        return luckyReward;
    }

    function calculateTotalLuckyReward() internal view returns (uint256) {
        uint256 totalLuckyReward = 0;
        uint256 roundId = getCurrentRoundId();
        for (uint256 i = 0; i < roundId; i++) { 
            totalLuckyReward += calculateLuckyReward(msg.sender, i);
        }
        return totalLuckyReward;
    }




    function getCurrentRoundId() public view returns (uint256) {
        return _roundId.current();
    }


    function getStakeAmount(uint256 roundId, uint256 day) public view returns (uint256) {
        return stakeAmount[roundId][day][msg.sender];
    }


    function getRoundPastTime() external view returns (uint256) {
        return (block.timestamp - START_ROUND_DATE);
    }


    function getDepositDate() internal view returns (uint256) {
        for (uint256 i = 1; i <= MAX_DATE; i++) { 
            if (block.timestamp >= START_ROUND_DATE && block.timestamp < START_ROUND_DATE + (i * 1 days)) { 
                return i;
            }
        }
    }


    function getTotalLuckyRewardPerDay(uint256 roundId) public view returns (uint256) {
        return (totalLuckyRevenue[roundId] / MAX_DATE);
    }


    function getLuckyBalance() external view returns (uint256) {
        return lucky.balanceOf(address(this));
    }


    function getLuckyBusdBalance() external view returns (uint256) {
        return luckyBusd.balanceOf(address(this));
    }


    function getPendingReward() external view returns (uint256) {
        UserInfo storage user = userInfo[msg.sender];
        if (user.amount == 0) {
            return user.pendingReward;
        }
        uint256 luckyReward = calculateTotalLuckyReward();
        uint256 luckyRewardDept = user.rewardDept;
        return (luckyReward - luckyRewardDept);
    }


    function getLuckyRewardPerRound(uint256 roundId) external view returns (uint256){
	    uint256 luckyReward = calculateLuckyReward(msg.sender, roundId);
	    return luckyReward;
    }


    function isStakeUpToDate(uint256 currentRoundId) internal view returns (bool) {
        return (userInfo[msg.sender].lastUpdateRoundId == currentRoundId);
    }




    function depositRevenue(
        InputToken[] calldata inputTokens,
        address[] calldata BUSDToOutputPath,
        uint256 minOutputAmount,
        uint256 winRate,
        uint256 TPV
    ) external payable isWhitelisted(msg.sender) {
        uint256 luckyRevenue;
        uint256 roundId = getCurrentRoundId();


        address[] memory _path = new address[](2);
            _path[0] = address(wNative);
            _path[1] = address(BUSD);


        if (msg.value > 0) {
            wNative.deposit{value: msg.value}();
            uint256 wNativeBalance = wNative.balanceOf(address(this));
            _swapExactNativeForBUSD(wNativeBalance, _path);
        }

        if (inputTokens.length > 0 ) {
            for (uint256 i; i < inputTokens.length; i++) {
                if (inputTokens[i].token == address(lucky)) { 
                    IERC20(lucky).safeTransferFrom(msg.sender, address(this), inputTokens[i].amount);
                    totalLuckyRevenue[roundId] += inputTokens[i].amount;
                    luckyRevenue += inputTokens[i].amount;
                } else if (inputTokens[i].token == address(BUSD)) { 
                    IERC20(BUSD).safeTransferFrom(msg.sender, address(this), inputTokens[i].amount);
                } else {  
                    _transferTokensToCave(inputTokens[i]);
                    _swapTokensForBUSD(inputTokens[i]);
                }
            }
        }

        uint256 BUSDBalance = BUSD.balanceOf(address(this));
        uint256 amountOut = _swapBUSDForToken( 
            BUSDBalance,
            BUSDToOutputPath
        );

        require(
            amountOut >= minOutputAmount,
            "Expect amountOut to be greater than minOutputAmount."
        );

        updatePoolInfo(winRate, TPV, BUSDBalance, roundId); 
        totalLuckyRevenue[roundId] += amountOut;
        luckyRevenue += amountOut;
        START_ROUND_DATE = block.timestamp;
        updateRoundId();
        uint256 currentRoundId = getCurrentRoundId();
        updateTotalStake(currentRoundId); 
        emit DistributeLuckyRevenue(msg.sender, address(this), luckyRevenue);
    }


    function _transferTokensToCave(InputToken calldata inputTokens) private {
            IERC20(inputTokens.token).safeTransferFrom(
                msg.sender,
                address(this),
                inputTokens.amount
            );
    }


    function _swapExactNativeForBUSD(uint256 amount, address[] memory path) private returns (uint256){
        if (amount == 0 || path[path.length - 1] == address(wNative)) {
            return amount;
        }
        wNative.approve(address(exchangeRouter), MAX_NUMBER);
        exchangeRouter.swapExactTokensForTokens(
            amount,
            0,
            path,
            address(this),
            block.timestamp + 60
        );
    }


    function _swapTokensForBUSD(InputToken calldata inputTokens) private {
        if (inputTokens.token != address(BUSD)) {
            IERC20(inputTokens.token).approve(address(exchangeRouter), MAX_NUMBER);
            exchangeRouter.swapExactTokensForTokens(
                inputTokens.amount,
                0, 
                inputTokens.tokenToBUSDPath,
                address(this),
                block.timestamp + 60
            );
        }
    }


    function _swapBUSDForToken(uint256 amount, address[] memory path)
        private
        returns (uint256)
    {
        if (amount == 0 || path[path.length - 1] == address(BUSD)) {
            return amount;
        }
        BUSD.approve(address(exchangeRouter), MAX_NUMBER);
        uint256[] memory amountOuts = exchangeRouter.swapExactTokensForTokens(
            amount,
            0,
            path,
            address(this),
            block.timestamp + 60
        );
        return amountOuts[amountOuts.length - 1];
    }
}

pragma solidity ^0.8.0;


abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        return msg.data;
    }
}


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor() {
        _setOwner(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        _setOwner(address(0));
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _setOwner(newOwner);
    }

    function _setOwner(address newOwner) private {
        address oldOwner = _owner;
        _owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }
}


abstract contract Withdrawable is Context, Ownable {


    address private _withdrawer;

    event WithdrawershipTransferred(address indexed previousWithdrawer, address indexed newWithdrawer);


    constructor () {
        address msgSender = _msgSender();
        _withdrawer = msgSender;
        emit WithdrawershipTransferred(address(0), msgSender);
    }


    function withdrawer() public view returns (address) {
        return _withdrawer;
    }


    modifier onlyWithdrawer() {
        require(_withdrawer == _msgSender(), "Withdrawable: caller is not the withdrawer");
        _;
    }


    function transferWithdrawership(address newWithdrawer) public virtual onlyOwner {
        require(newWithdrawer != address(0), "Withdrawable: new withdrawer is the zero address");

        emit WithdrawershipTransferred(_withdrawer, newWithdrawer);
        _withdrawer = newWithdrawer;
    }
}


abstract contract ReentrancyGuard {











    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor() {
        _status = _NOT_ENTERED;
    }


    modifier nonReentrant() {

        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");


        _status = _ENTERED;

        _;



        _status = _NOT_ENTERED;
    }
}


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount) external returns (bool);


    function allowance(address owner, address spender) external view returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(address indexed owner, address indexed spender, uint256 value);
}


library Address {

    function isContract(address account) internal view returns (bool) {




        uint256 size;
        assembly {
            size := extcodesize(account)
        }
        return size > 0;
    }


    function sendValue(address payable recipient, uint256 amount) internal {
        require(address(this).balance >= amount, "Address: insufficient balance");

        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Address: unable to send value, recipient may have reverted");
    }


    function functionCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionCall(target, data, "Address: low-level call failed");
    }


    function functionCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, 0, errorMessage);
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, value, "Address: low-level call with value failed");
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(address(this).balance >= value, "Address: insufficient balance for call");
        require(isContract(target), "Address: call to non-contract");

        (bool success, bytes memory returndata) = target.call{value: value}(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionStaticCall(address target, bytes memory data) internal view returns (bytes memory) {
        return functionStaticCall(target, data, "Address: low-level static call failed");
    }


    function functionStaticCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal view returns (bytes memory) {
        require(isContract(target), "Address: static call to non-contract");

        (bool success, bytes memory returndata) = target.staticcall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionDelegateCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionDelegateCall(target, data, "Address: low-level delegate call failed");
    }


    function functionDelegateCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(isContract(target), "Address: delegate call to non-contract");

        (bool success, bytes memory returndata) = target.delegatecall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }

    function _verifyCallResult(
        bool success,
        bytes memory returndata,
        string memory errorMessage
    ) private pure returns (bytes memory) {
        if (success) {
            return returndata;
        } else {

            if (returndata.length > 0) {


                assembly {
                    let returndata_size := mload(returndata)
                    revert(add(32, returndata), returndata_size)
                }
            } else {
                revert(errorMessage);
            }
        }
    }
}


library SafeERC20 {
    using Address for address;

    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transfer.selector, to, value));
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transferFrom.selector, from, to, value));
    }


    function safeApprove(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {



        require(
            (value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, value));
    }

    function safeIncreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance = token.allowance(address(this), spender) + value;
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }

    function safeDecreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        unchecked {
            uint256 oldAllowance = token.allowance(address(this), spender);
            require(oldAllowance >= value, "SafeERC20: decreased allowance below zero");
            uint256 newAllowance = oldAllowance - value;
            _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
        }
    }


    function _callOptionalReturn(IERC20 token, bytes memory data) private {




        bytes memory returndata = address(token).functionCall(data, "SafeERC20: low-level call failed");
        if (returndata.length > 0) {

            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }
    }
}

interface IWUSD is IERC20 {
    function mint(address account, uint256 amount) external;
    function burn(address account, uint256 amount) external;
}

interface IWswapRouter {
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint amountIn,
        uint amountOutMin,
        address[] calldata path,
        address to,
        uint deadline
    ) external;
}

contract WUSDMaster is Ownable, Withdrawable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IWUSD public immutable wusd;
    IERC20 public usdt;
    IERC20 public wex;
    IWswapRouter public immutable wswapRouter;
    address public treasury;
    address public strategist;

    address[] public swapPath;
    address[] public swapPathReverse;

    uint public wexPermille = 100;
    uint public treasuryPermille = 5;
    uint public feePermille = 2;

    uint256 public maxStakeAmount;

    mapping(address => uint256) public wusdClaimAmount;
    mapping(address => uint256) public wusdClaimBlock;
    mapping(address => uint256) public usdtClaimAmount;
    mapping(address => uint256) public usdtClaimBlock;

    event Stake(address indexed user, uint256 amount);
    event WusdClaim(address indexed user, uint256 amount);
    event Redeem(address indexed user, uint256 amount);
    event UsdtClaim(address indexed user, uint256 amount);
    event UsdtWithdrawn(uint256 amount);
    event WexWithdrawn(uint256 amount);
    event SwapPathChanged(address[] swapPath);
    event WexPermilleChanged(uint256 wexPermille);
    event TreasuryPermilleChanged(uint256 treasuryPermille);
    event FeePermilleChanged(uint256 feePermille);
    event TreasuryAddressChanged(address treasury);
    event StrategistAddressChanged(address strategist);
    event MaxStakeAmountChanged(uint256 maxStakeAmount);

    constructor(IWUSD _wusd, IERC20 _usdt, IERC20 _wex, IWswapRouter _wswapRouter, address _treasury, uint256 _maxStakeAmount) {
        require(
            address(_wusd) != address(0) &&
            address(_usdt) != address(0) &&
            address(_wex) != address(0) &&
            address(_wswapRouter) != address(0) &&
            _treasury != address(0),
            "zero address in constructor"
        );
        wusd = _wusd;
        usdt = _usdt;
        wex = _wex;
        wswapRouter = _wswapRouter;
        treasury = _treasury;
        swapPath = [address(usdt), address(wex)];
        swapPathReverse = [address(wex), address(usdt)];
        maxStakeAmount = _maxStakeAmount;
    }

    function setSwapPath(address[] calldata _swapPath) external onlyOwner {
        swapPath = _swapPath;

        emit SwapPathChanged(swapPath);
    }

    function setWexPermille(uint _wexPermille) external onlyOwner {
        require(_wexPermille <= 500, 'wexPermille too high!');
        wexPermille = _wexPermille;

        emit WexPermilleChanged(wexPermille);
    }

    function setTreasuryPermille(uint _treasuryPermille) external onlyOwner {
        require(_treasuryPermille <= 50, 'treasuryPermille too high!');
        treasuryPermille = _treasuryPermille;

        emit TreasuryPermilleChanged(treasuryPermille);
    }

    function setFeePermille(uint _feePermille) external onlyOwner {
        require(_feePermille <= 20, 'feePermille too high!');
        feePermille = _feePermille;

        emit FeePermilleChanged(feePermille);
    }

    function setTreasuryAddress(address _treasury) external onlyOwner {
        treasury = _treasury;

        emit TreasuryAddressChanged(treasury);
    }

    function setStrategistAddress(address _strategist) external onlyOwner {
        strategist = _strategist;

        emit StrategistAddressChanged(strategist);
    }

    function setMaxStakeAmount(uint256 _maxStakeAmount) external onlyOwner {
        maxStakeAmount = _maxStakeAmount;

        emit MaxStakeAmountChanged(maxStakeAmount);
    }

    function stake(uint256 amount) external nonReentrant {
        require(amount > 0, 'amount cant be zero');
        require(wusdClaimAmount[msg.sender] == 0, 'you have to claim first');
        require(amount <= maxStakeAmount, 'amount too high');

        usdt.safeTransferFrom(msg.sender, address(this), amount);
        if(feePermille > 0) {
            uint256 feeAmount = amount * feePermille / 1000;
            usdt.safeTransfer(treasury, feeAmount);
            amount = amount - feeAmount;
        }
        uint256 wexAmount = amount * wexPermille / 1000;
        usdt.approve(address(wswapRouter), wexAmount);
        wswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            wexAmount,
            0,
            swapPath,
            address(this),
            block.timestamp
        );

        wusdClaimAmount[msg.sender] = amount;
        wusdClaimBlock[msg.sender] = block.number;

        emit Stake(msg.sender, amount);
    }

    function claimWusd() external nonReentrant {
        require(wusdClaimAmount[msg.sender] > 0, 'there is nothing to claim');
        require(wusdClaimBlock[msg.sender] < block.number, 'you cant claim yet');

        uint256 amount = wusdClaimAmount[msg.sender];
        wusdClaimAmount[msg.sender] = 0;
        wusd.mint(msg.sender, amount);

        emit WusdClaim(msg.sender, amount);
    }

    function redeem(uint256 amount) external nonReentrant {
        require(amount > 0, 'amount cant be zero');
        require(usdtClaimAmount[msg.sender] == 0, 'you have to claim first');

        wusd.burn(msg.sender, amount);
        usdtClaimAmount[msg.sender] = amount;
        usdtClaimBlock[msg.sender] = block.number;

        emit Redeem(msg.sender, amount);
    }

    function claimUsdt() external nonReentrant {
        require(usdtClaimAmount[msg.sender] > 0, 'there is nothing to claim');
        require(usdtClaimBlock[msg.sender] < block.number, 'you cant claim yet');

        uint256 amount = usdtClaimAmount[msg.sender];
        usdtClaimAmount[msg.sender] = 0;

        uint256 usdtTransferAmount = amount * (1000 - wexPermille - treasuryPermille) / 1000;
        uint256 usdtTreasuryAmount = amount * treasuryPermille / 1000;
        uint256 wexTransferAmount = wex.balanceOf(address(this)) * amount / (wusd.totalSupply() + amount);
        usdt.safeTransfer(treasury, usdtTreasuryAmount);
        usdt.safeTransfer(msg.sender, usdtTransferAmount);
        wex.approve(address(wswapRouter), wexTransferAmount);
        wswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            wexTransferAmount,
            0,
            swapPathReverse,
            msg.sender,
            block.timestamp
        );

        emit UsdtClaim(msg.sender, amount);
    }

    function withdrawUsdt(uint256 amount) external onlyOwner {
        require(strategist != address(0), 'strategist not set');
        usdt.safeTransfer(strategist, amount);

        emit UsdtWithdrawn(amount);
    }

    function withdrawWex(uint256 amount) external onlyWithdrawer {
        wex.safeTransfer(msg.sender, amount);

        emit WexWithdrawn(amount);
    }
}

pragma solidity ^0.8.0;

import "./modules/kap20/interfaces/IKAP20.sol";
import "./modules/kap20/interfaces/IKToken.sol";
import "./modules/erc20/interfaces/IEIP20NonStandard.sol";
import "./interfaces/IInterestRateModel.sol";
import "./interfaces/ILKAP20.sol";
import "./abstracts/LendingContract.sol";

contract KAP20Lending is LendingContract {
    constructor(
        address underlyingToken_,
        address controller_,
        address interestRateModel_,
        uint256 initialExchangeRateMantissa_,
        string memory lTokenName_,
        string memory lTokenSymbol_,
        uint8 lTokenDecimals_,
        address committee_,
        address adminRouter_,
        address kyc_,
        uint256 acceptedKycLevel_
    )
        LendingContract(
            controller_,
            interestRateModel_,
            initialExchangeRateMantissa_,
            lTokenName_,
            lTokenSymbol_,
            lTokenDecimals_,
            committee_,
            adminRouter_,
            kyc_,
            acceptedKycLevel_
        )
    {

        underlyingToken = underlyingToken_;
        IKAP20(underlyingToken).totalSupply();
    }



    function deposit(uint256 depositAmount, address sender)
        external
        returns (uint256)
    {
        uint256 err;
        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            (err, ) = depositInternal(
                sender,
                depositAmount,
                TransferMethod.BK_NEXT
            );
        } else {
            (err, ) = depositInternal(
                msg.sender,
                depositAmount,
                TransferMethod.METAMASK
            );
        }

        return err;
    }

    function withdraw(uint256 withdrawTokens, address payable sender)
        external
        returns (uint256)
    {
        uint256 err;
        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            err = withdrawInternal(sender, withdrawTokens, TransferMethod.BK_NEXT);
        } else {
            err = withdrawInternal(payable(msg.sender), withdrawTokens, TransferMethod.METAMASK);
        }

        return err;
    }

    function withdrawUnderlying(uint256 withdrawAmount, address payable sender)
        external
        returns (uint256)
    {
        uint256 err;
        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            err = withdrawUnderlyingInternal(sender, withdrawAmount, TransferMethod.BK_NEXT);
        } else {
            err = withdrawUnderlyingInternal(
                payable(msg.sender),
                withdrawAmount,
                TransferMethod.METAMASK
            );
        }
        return err;
    }

    function borrow(uint256 borrowAmount, address payable sender)
        external
        returns (uint256)
    {
        uint256 err;
        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            err = borrowInternal(sender, borrowAmount, TransferMethod.BK_NEXT);
        } else {
            err = borrowInternal(payable(msg.sender), borrowAmount, TransferMethod.METAMASK);
        }
        return err;
    }

    function repayBorrow(uint256 repayAmount, address sender)
        external
        returns (uint256)
    {
        uint256 err;
        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            (err, ) = repayBorrowInternal(
                sender,
                repayAmount,
                TransferMethod.BK_NEXT
            );
        } else {
            (err, ) = repayBorrowInternal(
                msg.sender,
                repayAmount,
                TransferMethod.METAMASK
            );
        }
        return err;
    }

    function repayBorrowBehalf(
        address borrower,
        uint256 repayAmount,
        address sender
    ) external returns (uint256) {
        uint256 err;
        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            (err, ) = repayBorrowBehalfInternal(
                sender,
                borrower,
                repayAmount,
                TransferMethod.BK_NEXT
            );
        } else {
            (err, ) = repayBorrowBehalfInternal(
                msg.sender,
                borrower,
                repayAmount,
                TransferMethod.METAMASK
            );
        }
        return err;
    }

    function liquidateBorrow(address borrower, address payable sender)
        external
        returns (uint256)
    {
        uint256 err;

        if (adminRouter.isSuperAdmin(msg.sender, PROJECT)) {
            requireKYC(sender);
            (err, ) = liquidateBorrowInternal(sender, borrower, TransferMethod.BK_NEXT);
        } else {
            (err, ) = liquidateBorrowInternal(payable(msg.sender), borrower, TransferMethod.METAMASK);
        }

        return err;
    }

    function sweepToken(IEIP20NonStandard token) external onlyAdmin {
        require(
            address(token) != underlyingToken,
            "Can not sweep underlying token"
        );
        uint256 balance = token.balanceOf(address(this));
        token.transfer(msg.sender, balance);
    }



    function getCashPrior() internal view override returns (uint256) {
        return IKAP20(underlyingToken).balanceOf(address(this));
    }


    function doTransferIn(
        address from,
        uint256 amount,
        TransferMethod method
    ) internal override returns (uint256) {
        if (method == TransferMethod.BK_NEXT) {
            return doTransferInBKNext(from, amount);
        } else {
            return doTransferInMetamask(from, amount);
        }
    }

    function doTransferInBKNext(address from, uint256 amount)
        private
        returns (uint256)
    {
        IKAP20 token = IKAP20(underlyingToken);
        uint256 balanceBefore = token.balanceOf(address(this));
        IKToken(underlyingToken).externalTransfer(from, address(this), amount);

        uint256 balanceAfter = token.balanceOf(address(this));
        require(balanceAfter >= balanceBefore, "Transfer in overflow");
        return balanceAfter - balanceBefore; 
    }

    function doTransferInMetamask(address from, uint256 amount)
        private
        returns (uint256)
    {
        IEIP20NonStandard token = IEIP20NonStandard(underlyingToken);
        uint256 balanceBefore = IKAP20(underlyingToken).balanceOf(
            address(this)
        );

        token.transferFrom(from, address(this), amount);

        bool success;
        assembly {
            switch returndatasize()
            case 0 {

                success := not(0) 
            }
            case 32 {

                returndatacopy(0, 0, 32)
                success := mload(0) 
            }
            default {

                revert(0, 0)
            }
        }
        require(success, "Transfer in failed");


        uint256 balanceAfter = IKAP20(underlyingToken).balanceOf(address(this));
        require(balanceAfter >= balanceBefore, "Transfer in overflow");
        return balanceAfter - balanceBefore; 
    }


    function doTransferOut(address payable to, uint256 amount, TransferMethod method)
        internal
        override
    {
        method; 

        IEIP20NonStandard token = IEIP20NonStandard(underlyingToken);
        token.transfer(to, amount);

        bool success;
        assembly {
            switch returndatasize()
            case 0 {

                success := not(0) 
            }
            case 32 {

                returndatacopy(0, 0, 32)
                success := mload(0) 
            }
            default {

                revert(0, 0)
            }
        }

        require(success, "Transfer out failed");
    }
}

pragma solidity ^0.4.15;

import 'zeppelin-solidity/contracts/math/SafeMath.sol';
import "./Haltable.sol";
import "./PricingStrategy.sol";
import "./FinalizeAgent.sol";
import "./FractionalERC20.sol";



contract Crowdsale is Haltable {

  uint public constant TIME_PERIOD_IN_SEC = 1 days;


  uint public baseEthCap;


  uint public MAX_INVESTMENTS_BEFORE_MULTISIG_CHANGE = 5;

  using SafeMath for uint;


  FractionalERC20 public token;


  PricingStrategy public pricingStrategy;


  FinalizeAgent public finalizeAgent;


  address public multisigWallet;


  uint public minimumFundingGoal;


  uint public startsAt;


  uint public endsAt;


  uint public tokensSold = 0;


  uint public weiRaised = 0;


  uint public presaleWeiRaised = 0;


  uint public investorCount = 0;


  uint public loadedRefund = 0;


  uint public weiRefunded = 0;


  bool public finalized;


  bool public requireCustomerId;


  bool public requiredSignedAddress;


  address public signerAddress;


  mapping (address => uint256) public investedAmountOf;


  mapping (address => uint256) public tokenAmountOf;


  mapping (address => bool) public earlyParticipantWhitelist;


  mapping (address => bool) public whitelist;


  uint public ownerTestValue;


  enum State{Unknown, Preparing, PreFunding, Funding, Success, Failure, Finalized, Refunding}


  event Invested(address investor, uint weiAmount, uint tokenAmount, uint128 customerId);


  event Refund(address investor, uint weiAmount);


  event InvestmentPolicyChanged(bool newRequireCustomerId, bool newRequiredSignedAddress, address newSignerAddress);


  event Whitelisted(address addr, bool status);


  event EndsAtChanged(uint newEndsAt);


  event BaseEthCapChanged(uint newBaseEthCap);

  function Crowdsale(address _token, PricingStrategy _pricingStrategy, address _multisigWallet, uint _start, uint _end, uint _minimumFundingGoal, uint _baseEthCap) {

    owner = msg.sender;

    baseEthCap = _baseEthCap;

    token = FractionalERC20(_token);

    setPricingStrategy(_pricingStrategy);

    multisigWallet = _multisigWallet;
    if (multisigWallet == 0) {
        revert();
    }

    if (_start == 0) {
        revert();
    }

    startsAt = _start;

    if (_end == 0) {
        revert();
    }

    endsAt = _end;


    if (startsAt >= endsAt) {
        revert();
    }


    minimumFundingGoal = _minimumFundingGoal;
  }

  function() payable {
    buy();
  }


  function investInternal(address receiver, uint128 customerId) stopInEmergency private {


    if (getState() == State.PreFunding) {

      if (!earlyParticipantWhitelist[receiver]) {
        revert();
      }
    } else if (getState() == State.Funding) {

      if (!whitelist[receiver]) {
        revert();
      }


    } else {

      revert();
    }

    uint weiAmount = msg.value;

    uint currentEthCap = getCurrentEthCap();
    if (weiAmount > currentEthCap) {

      revert();
    }


    uint tokenAmount = pricingStrategy.calculatePrice(weiAmount, weiRaised - presaleWeiRaised, tokensSold, msg.sender, token.decimals());

    if (tokenAmount == 0) {

      revert();
    }

    if (investedAmountOf[receiver] == 0) {

       investorCount++;
    }


    investedAmountOf[receiver] = investedAmountOf[receiver].add(weiAmount);

    if (investedAmountOf[receiver] > currentEthCap) {

      revert();
    }

    tokenAmountOf[receiver] = tokenAmountOf[receiver].add(tokenAmount);



    weiRaised = weiRaised.add(weiAmount);
    tokensSold = tokensSold.add(tokenAmount);

    if (pricingStrategy.isPresalePurchase(receiver)) {
        presaleWeiRaised = presaleWeiRaised.add(weiAmount);
    }


    if (isBreakingCap(weiAmount, tokenAmount, weiRaised, tokensSold)) {
      revert();
    }

    assignTokens(receiver, tokenAmount);


    if (!multisigWallet.send(weiAmount)) 
      revert();


    Invested(receiver, weiAmount, tokenAmount, customerId);
  }

  function getCurrentEthCap() public constant returns (uint) {
    if (block.timestamp < startsAt) 
      return 0;
    uint timeSinceStart = block.timestamp.sub(startsAt);
    uint currentPeriod = timeSinceStart.div(TIME_PERIOD_IN_SEC).add(1);
    uint ethCap = baseEthCap.mul((2**currentPeriod).sub(1));
    return ethCap;
  }


  function preallocate(address receiver, uint fullTokens, uint weiPrice) public onlyOwner {

    uint tokenAmount = fullTokens * 10**token.decimals();
    uint weiAmount = weiPrice * fullTokens; 

    weiRaised = weiRaised.add(weiAmount);
    tokensSold = tokensSold.add(tokenAmount);

    investedAmountOf[receiver] = investedAmountOf[receiver].add(weiAmount);
    tokenAmountOf[receiver] = tokenAmountOf[receiver].add(tokenAmount);

    assignTokens(receiver, tokenAmount);


    Invested(receiver, weiAmount, tokenAmount, 0);
  }


  function investWithSignedAddress(address addr, uint128 customerId, uint8 v, bytes32 r, bytes32 s) public payable {
     bytes32 hash = sha256(addr);
     if (ecrecover(hash, v, r, s) != signerAddress) 
      revert();
     if (customerId == 0) 
      revert();  
     investInternal(addr, customerId);
  }


  function investWithCustomerId(address addr, uint128 customerId) public payable {
    if (requiredSignedAddress) 
      revert(); 
    if (customerId == 0) 
      revert();  
    investInternal(addr, customerId);
  }


  function invest(address addr) public payable {
    if (requireCustomerId) 
      revert(); 
    if (requiredSignedAddress) 
      revert(); 
    investInternal(addr, 0);
  }


  function buyWithSignedAddress(uint128 customerId, uint8 v, bytes32 r, bytes32 s) public payable {
    investWithSignedAddress(msg.sender, customerId, v, r, s);
  }


  function buyWithCustomerId(uint128 customerId) public payable {
    investWithCustomerId(msg.sender, customerId);
  }


  function buy() public payable {
    invest(msg.sender);
  }


  function finalize() public inState(State.Success) onlyOwner stopInEmergency {


    if (finalized) {
      revert();
    }


    if (address(finalizeAgent) != 0) {
      finalizeAgent.finalizeCrowdsale();
    }

    finalized = true;
  }


  function setFinalizeAgent(FinalizeAgent addr) onlyOwner {
    finalizeAgent = addr;


    if (!finalizeAgent.isFinalizeAgent()) {
      revert();
    }
  }


  function setRequireCustomerId(bool value) onlyOwner {
    requireCustomerId = value;
    InvestmentPolicyChanged(requireCustomerId, requiredSignedAddress, signerAddress);
  }


  function setRequireSignedAddress(bool value, address _signerAddress) onlyOwner {
    requiredSignedAddress = value;
    signerAddress = _signerAddress;
    InvestmentPolicyChanged(requireCustomerId, requiredSignedAddress, signerAddress);
  }


  function setEarlyParticipantWhitelist(address addr, bool status) onlyOwner {
    earlyParticipantWhitelist[addr] = status;
    Whitelisted(addr, status);
  }


  function addToWhitelist(address addr, bool status) onlyOwner {
    whitelist[addr] = status;
    Whitelisted(addr, status);
  }


  function addAllToWhitelist(address[] addresses, bool status) onlyOwner {
    for (uint index = 0; index < addresses.length; index++) {
      addToWhitelist(addresses[index], status);
    }
  }


  function setBaseEthCap(uint _baseEthCap) onlyOwner {
    if (_baseEthCap == 0) 
      revert();
    baseEthCap = _baseEthCap;
    BaseEthCapChanged(baseEthCap);
  }


  function setEndsAt(uint time) onlyOwner {
    if (now > time) {
      revert(); 
    }

    endsAt = time;
    EndsAtChanged(endsAt);
  }


  function setPricingStrategy(PricingStrategy _pricingStrategy) onlyOwner {
    pricingStrategy = _pricingStrategy;


    if (!pricingStrategy.isPricingStrategy()) {
      revert();
    }
  }


  function setMultisig(address addr) public onlyOwner {


    if (investorCount > MAX_INVESTMENTS_BEFORE_MULTISIG_CHANGE) {
      revert();
    }

    multisigWallet = addr;
  }


  function loadRefund() public payable inState(State.Failure) {
    if (msg.value == 0) 
      revert();
    loadedRefund = loadedRefund.add(msg.value);
  }


  function refund() public inState(State.Refunding) {
    uint256 weiValue = investedAmountOf[msg.sender];
    if (weiValue == 0) 
      revert();
    investedAmountOf[msg.sender] = 0;
    weiRefunded = weiRefunded.add(weiValue);
    Refund(msg.sender, weiValue);
    if (!msg.sender.send(weiValue)) 
      revert();
  }


  function isMinimumGoalReached() public constant returns (bool reached) {
    return weiRaised >= minimumFundingGoal;
  }


  function isFinalizerSane() public constant returns (bool sane) {
    return finalizeAgent.isSane();
  }


  function isPricingSane() public constant returns (bool sane) {
    return pricingStrategy.isSane(address(this));
  }


  function getState() public constant returns (State) {
    if (finalized) 
      return State.Finalized;
    else if (address(finalizeAgent) == 0) 
      return State.Preparing;
    else if (!finalizeAgent.isSane()) 
      return State.Preparing;
    else if (!pricingStrategy.isSane(address(this))) 
      return State.Preparing;
    else if (block.timestamp < startsAt) 
      return State.PreFunding;
    else if (block.timestamp <= endsAt && !isCrowdsaleFull()) 
      return State.Funding;
    else if (isMinimumGoalReached()) 
      return State.Success;
    else if (!isMinimumGoalReached() && weiRaised > 0 && loadedRefund >= weiRaised) 
      return State.Refunding;
    else 
      return State.Failure;
  }


  function setOwnerTestValue(uint val) onlyOwner {
    ownerTestValue = val;
  }


  function isCrowdsale() public constant returns (bool) {
    return true;
  }






  modifier inState(State state) {
    if (getState() != state) 
      revert();
    _;
  }







  function isBreakingCap(uint weiAmount, uint tokenAmount, uint weiRaisedTotal, uint tokensSoldTotal) constant returns (bool limitBroken);


  function isCrowdsaleFull() public constant returns (bool);


  function assignTokens(address receiver, uint tokenAmount) private;
}

pragma solidity ^0.8.0;

import './ERC721Time.sol';
import '@openzeppelin/contracts/token/ERC721/extensions/IERC721Enumerable.sol';


abstract contract ERC721Enumerable is ERC721Time, IERC721Enumerable {

    mapping(address => mapping(uint256 => uint256)) private _ownedTokens;


    mapping(uint256 => uint256) private _ownedTokensIndex;


    uint256[] private _allTokens;


    mapping(uint256 => uint256) private _allTokensIndex;


    function supportsInterface(bytes4 interfaceId)
        public
        view
        virtual
        override(IERC165, ERC721Time)
        returns (bool)
    {
        return
            interfaceId == type(IERC721Enumerable).interfaceId ||
            super.supportsInterface(interfaceId);
    }


    function tokenOfOwnerByIndex(address owner, uint256 index)
        public
        view
        virtual
        override
        returns (uint256)
    {
        require(index < ERC721Time.balanceOf(owner), 'ERC721Enumerable: owner index out of bounds');
        return _ownedTokens[owner][index];
    }


    function totalSupply() public view virtual override returns (uint256) {
        return _allTokens.length;
    }


    function tokenByIndex(uint256 index) public view virtual override returns (uint256) {
        require(
            index < ERC721Enumerable.totalSupply(),
            'ERC721Enumerable: global index out of bounds'
        );
        return _allTokens[index];
    }


    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId
    ) internal virtual override {
        super._beforeTokenTransfer(from, to, tokenId);

        if (from == address(0)) {
            _addTokenToAllTokensEnumeration(tokenId);
        } else if (from != to) {
            _removeTokenFromOwnerEnumeration(from, tokenId);
        }
        if (to == address(0)) {
            _removeTokenFromAllTokensEnumeration(tokenId);
        } else if (to != from) {
            _addTokenToOwnerEnumeration(to, tokenId);
        }
    }


    function _addTokenToOwnerEnumeration(address to, uint256 tokenId) private {
        uint256 length = ERC721Time.balanceOf(to);
        _ownedTokens[to][length] = tokenId;
        _ownedTokensIndex[tokenId] = length;
    }


    function _addTokenToAllTokensEnumeration(uint256 tokenId) private {
        _allTokensIndex[tokenId] = _allTokens.length;
        _allTokens.push(tokenId);
    }


    function _removeTokenFromOwnerEnumeration(address from, uint256 tokenId) private {



        uint256 lastTokenIndex = ERC721Time.balanceOf(from) - 1;
        uint256 tokenIndex = _ownedTokensIndex[tokenId];


        if (tokenIndex != lastTokenIndex) {
            uint256 lastTokenId = _ownedTokens[from][lastTokenIndex];

            _ownedTokens[from][tokenIndex] = lastTokenId; 
            _ownedTokensIndex[lastTokenId] = tokenIndex; 
        }


        delete _ownedTokensIndex[tokenId];
        delete _ownedTokens[from][lastTokenIndex];
    }


    function _removeTokenFromAllTokensEnumeration(uint256 tokenId) private {



        uint256 lastTokenIndex = _allTokens.length - 1;
        uint256 tokenIndex = _allTokensIndex[tokenId];




        uint256 lastTokenId = _allTokens[lastTokenIndex];

        _allTokens[tokenIndex] = lastTokenId; 
        _allTokensIndex[lastTokenId] = tokenIndex; 


        delete _allTokensIndex[tokenId];
        _allTokens.pop();
    }
}

