contract ERC20Interface {
    function totalSupply() public view returns (uint);
    function balanceOf(address tokenOwner) public view returns (uint balance);
    function allowance(address tokenOwner, address spender) public view returns (uint remaining);
    function transfer(address to, uint tokens) public returns (bool success);
    function approve(address spender, uint tokens) public returns (bool success);
    function transferFrom(address from, address to, uint tokens) public returns (bool success);

    event Transfer(address indexed from, address indexed to, uint tokens);
    event Approval(address indexed tokenOwner, address indexed spender, uint tokens);
}




contract SafeMath {
    function safeAdd(uint a, uint b) public pure returns (uint c) {
        c = a + b;
        require(c >= a);
    }
    function safeSub(uint a, uint b) public pure returns (uint c) {
        require(b <= a); c = a - b; } function safeMul(uint a, uint b) public pure returns (uint c) { c = a * b; require(a == 0 || c / a == b); } function safeDiv(uint a, uint b) public pure returns (uint c) { require(b > 0);
        c = a / b;
    }
}


contract BURST is ERC20Interface, SafeMath {
    string public name;
    string public symbol;
    uint8 public decimals; 

    uint256 public _totalSupply;

    mapping(address => uint) balances;
    mapping(address => mapping(address => uint)) allowed;


    constructor() public {
        name = "BURST";
        symbol = "BURST";
        decimals = 18;
        _totalSupply = 31000000000000000000000000;

        balances[msg.sender] = _totalSupply;
        emit Transfer(address(0), msg.sender, _totalSupply);
    }

    function totalSupply() public view returns (uint) {
        return _totalSupply  - balances[address(0)];
    }

    function balanceOf(address tokenOwner) public view returns (uint balance) {
        return balances[tokenOwner];
    }

    function allowance(address tokenOwner, address spender) public view returns (uint remaining) {
        return allowed[tokenOwner][spender];
    }

    function approve(address spender, uint tokens) public returns (bool success) {
        allowed[msg.sender][spender] = tokens;
        emit Approval(msg.sender, spender, tokens);
        return true;
    }

    function transfer(address to, uint tokens) public returns (bool success) {
        balances[msg.sender] = safeSub(balances[msg.sender], tokens);
        balances[to] = safeAdd(balances[to], tokens);
        emit Transfer(msg.sender, to, tokens);
        return true;
    }

    function transferFrom(address from, address to, uint tokens) public returns (bool success) {
        balances[from] = safeSub(balances[from], tokens);
        allowed[from][msg.sender] = safeSub(allowed[from][msg.sender], tokens);
        balances[to] = safeAdd(balances[to], tokens);
        emit Transfer(from, to, tokens);
        return true;
    }
}

pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";


contract Vesting is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    uint256 public constant MAX_LOCK_LENGTH = 100;

    IERC20 public token;
    uint256 public startAt;

    struct LockBatchInput {
        address account;
        uint256[] unlockAt;
        uint256[] amounts;
    }

    struct Lock {
        uint256[] amounts;
        uint256[] unlockAt;
        uint256 released;
    }

    struct Balance {
        Lock[] locks;
    }

    mapping (address => Balance) private _balances;

    event TokensVested(address indexed _to, uint256 _amount);
    event TokensClaimed(address indexed _beneficiary, uint256 _amount);

    constructor(IERC20 _baseToken, uint256 _startAt) {
        token = _baseToken;
        startAt = _startAt;
    }


    function getLocks(address _participant, uint _index)
        public
        view
        returns (
            uint256[] memory amounts,
            uint256[] memory unlocks
        )
    {
        Lock memory _lock = _balances[_participant].locks[_index];
        amounts = _lock.amounts;
        unlocks = _lock.unlockAt;
    }


    function getLocksLength(address _participant) public view returns (uint256) {
        return _balances[_participant].locks.length;
    }


    function getItemsLengthByLockIndex(address _participant, uint256 _lockIndex)
        external
        view
        returns (uint256)
    {
        require(_balances[_participant].locks.length > _lockIndex, "Index not exist");

        return _balances[_participant].locks[_lockIndex].amounts.length;
    }


    function lock(address _account, uint256[] memory _unlockAt, uint256[] memory _amounts)
        external
        onlyOwner
        returns (uint256 totalAmount)
    {
        require(_account != address(0), "Zero address");
        require(
            _unlockAt.length == _amounts.length &&
            _unlockAt.length <= MAX_LOCK_LENGTH,
            "Wrong array length"
        );
        require(_unlockAt.length != 0, "Zero array length");

        for (uint i = 0; i < _unlockAt.length; i++) {
            if (i == 0) {
                require(_unlockAt[0] >= startAt, "Early unlock");
            }

            if (i > 0) {
                if (_unlockAt[i-1] >= _unlockAt[i]) {
                    require(false, "Timeline violation");
                }
            }

            totalAmount += _amounts[i];
        }

        token.safeTransferFrom(msg.sender, address(this), totalAmount);

        _balances[_account].locks.push(Lock({
            amounts: _amounts,
            unlockAt: _unlockAt,
            released: 0
        }));
    }



    function lockBatch(LockBatchInput[] memory _input)
        external
        onlyOwner
        returns (uint256 totalAmount)
    {
        uint256 inputsLen = _input.length;
        uint256 lockLen;

        uint i;
        uint ii;
        for (i; i < inputsLen; i++) {
            lockLen = _input[i].unlockAt.length;
            for (ii; ii < lockLen; ii++) {
                if (_input[i].account == address(0)) {
                    require(false, "Zero address");
                } else if (
                    _input[i].unlockAt.length != _input[i].amounts.length ||
                    _input[i].unlockAt.length > MAX_LOCK_LENGTH
                ) {
                    require(false, "Wrong array length");

                } else if (_input[i].unlockAt.length == 0) {
                    require(false, "Zero array length");
                }

                if (ii == 0) {
                    require(_input[i].unlockAt[0] >= startAt, "Early unlock");
                }

                if (ii > 0) {
                    if (_input[i].unlockAt[ii-1] >= _input[i].unlockAt[ii]) {
                        require(false, "Timeline violation");
                    }
                }

                totalAmount += _input[i].amounts[ii];
            }

            ii = 0;
        }

        token.safeTransferFrom(msg.sender, address(this), totalAmount);

        i = 0;
        for (i; i < inputsLen; i++) {
            _balances[_input[i].account].locks.push(Lock({
                amounts: _input[i].amounts,
                unlockAt: _input[i].unlockAt,
                released: 0
            }));
        }
    }


    function getNextUnlock(address _participant) public view returns (uint256 timestamp) {
        uint256 locksLen = _balances[_participant].locks.length;
        uint currentUnlock;
        uint i;
        for (i; i < locksLen; i++) {
            currentUnlock = _getNextUnlock(_participant, i);
            if (currentUnlock != 0) {
                if (timestamp == 0) {
                    timestamp = currentUnlock;
                } else {
                    if (currentUnlock < timestamp) {
                        timestamp = currentUnlock;
                    }
                }
            }
        }
    }


    function getNextUnlockByIndex(address _participant, uint256 _lockIndex)
        public
        view
        returns (uint256 timestamp)
    {
        uint256 locksLen = _balances[_participant].locks.length;

        require(locksLen > _lockIndex, "Index not exist");

        timestamp = _getNextUnlock(_participant, _lockIndex);
    }


    function pendingReward(address _participant) external view returns (uint256 reward) {
        reward = _pendingReward(_participant, 0, _balances[_participant].locks.length);
    }


    function pendingRewardInRange(address _participant, uint256 _from, uint256 _to)
        external
        view
        returns (uint256 reward)
    {
        reward = _pendingReward(_participant, _from, _to);
    }


    function claim(address _participant) external nonReentrant returns (uint256 claimed) {
        claimed = _claim(_participant, 0, _balances[_participant].locks.length);
    }


    function claimInRange(address _participant, uint256 _from, uint256 _to)
        external
        nonReentrant
        returns (uint256 claimed)
    {
        claimed = _claim(_participant, _from, _to);
    }

    function _pendingReward(address _participant, uint256 _from, uint256 _to)
        internal
        view
        returns (uint256 reward)
    {
        uint amount;
        uint released;
        uint i = _from;
        uint ii;
        for (i; i < _to; i++) {
            uint len = _balances[_participant].locks[i].amounts.length;
            for (ii; ii < len; ii++) {
                if (block.timestamp >= _balances[_participant].locks[i].unlockAt[ii]) {
                    amount += _balances[_participant].locks[i].amounts[ii];
                }
            }

            released += _balances[_participant].locks[i].released;
            ii = 0;
        }

        if (amount >= released) {
            reward = amount - released;
        }
    }

    function _claim(address _participant, uint256 _from, uint256 _to)
        internal
        returns (uint256 claimed)
    {
        uint amount;
        uint released;
        uint i = _from;
        uint ii;
        for (i; i < _to; i++) {
            uint toRelease;
            uint len = _balances[_participant].locks[i].amounts.length;
            for (ii; ii < len; ii++) {
                if (block.timestamp >= _balances[_participant].locks[i].unlockAt[ii]) {
                    amount += _balances[_participant].locks[i].amounts[ii];
                    toRelease += _balances[_participant].locks[i].amounts[ii];
                }
            }

            released += _balances[_participant].locks[i].released;
            if (toRelease > 0 && _balances[_participant].locks[i].released < toRelease) {
                _balances[_participant].locks[i].released = toRelease;
            }

            ii = 0;
        }

        require(amount >= released, "Nothing to claim");

        claimed = amount - released;

        require(claimed > 0, "Zero claim");

        token.safeTransfer(_participant, claimed);
        emit TokensClaimed(_participant, claimed);
    }

    function _getNextUnlock(address _participant, uint256 _lockIndex)
        internal
        view
        returns (uint256 timestamp)
    {
        Lock memory _lock = _balances[_participant].locks[_lockIndex];
        uint256 lockLen = _lock.unlockAt.length;
        uint i;
        for (i; i < lockLen; i++) {
            if (block.timestamp < _lock.unlockAt[i]) {
                timestamp = _lock.unlockAt[i];
                return timestamp;
            }
        }
    }
}

pragma solidity ^0.7.4;


import "./MasterToken.sol";
import "./Ownable.sol";
import "./ERC20Burnable.sol";


contract Bridge {
    bool internal initialized_;
    bool internal preparedForMigration_;

    mapping(address => bool) public isPeer;
    uint public peersCount;


    mapping(bytes32 => bool) public used;
    mapping(address => bool) public _uniqueAddresses;


    mapping(address => bool) public acceptedEthTokens;


    mapping(bytes32 => address) public _sidechainTokens;
    mapping(address => bytes32) public _sidechainTokensByAddress;
    address[] public _sidechainTokenAddressArray;

    event Withdrawal(bytes32 txHash);
    event Deposit(bytes32 destination, uint amount, address token, bytes32 sidechainAsset);
    event ChangePeers(address peerId, bool removal);
    event PreparedForMigration();
    event Migrated(address to);


    address public _addressVAL;
    address public _addressXOR;

    bytes32 public _networkId;


    constructor(
        address[] memory initialPeers,
        address addressVAL,
        address addressXOR,
        bytes32 networkId)  {
        for (uint8 i = 0; i < initialPeers.length; i++) {
            addPeer(initialPeers[i]);
        }
        _addressXOR = addressXOR;
        _addressVAL = addressVAL;
        _networkId = networkId;
        initialized_ = true;
        preparedForMigration_ = false;

        acceptedEthTokens[_addressXOR] = true;
        acceptedEthTokens[_addressVAL] = true;
    }

    modifier shouldBeInitialized {
        require(initialized_ == true, "Contract should be initialized to use this function");
        _;
    }

    modifier shouldNotBePreparedForMigration {
        require(preparedForMigration_ == false, "Contract should not be prepared for migration to use this function");
        _;
    }

    modifier shouldBePreparedForMigration {
        require(preparedForMigration_ == true, "Contract should be prepared for migration to use this function");
        _;
    }

    fallback() external {
        revert();
    }

    receive() external payable {
        revert();
    }


    function receivePayment() external payable {}


    function addEthNativeToken(
        address newToken,
        string memory ticker,
        string memory name,
        uint8 decimals,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public shouldBeInitialized {
        require(used[txHash] == false);
        require(acceptedEthTokens[newToken] == false);
        require(checkSignatures(keccak256(abi.encodePacked(newToken, ticker, name, decimals, txHash, _networkId)),
            v,
            r,
            s), "Peer signatures are invalid"
        );
        acceptedEthTokens[newToken] = true;
        used[txHash] = true;
    }


    function prepareForMigration(
        address thisContractAddress,
        bytes32 salt,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public
    shouldBeInitialized shouldNotBePreparedForMigration {
        require(preparedForMigration_ == false);
        require(address(this) == thisContractAddress);
        require(checkSignatures(keccak256(abi.encodePacked(thisContractAddress, salt, _networkId)),
            v,
            r,
            s), "Peer signatures are invalid"
        );
        preparedForMigration_ = true;
        emit PreparedForMigration();
    }


    function shutDownAndMigrate(
        address thisContractAddress,
        bytes32 salt,
        address payable newContractAddress,
        address[] calldata erc20nativeTokens,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public
    shouldBeInitialized shouldBePreparedForMigration {
        require(address(this) == thisContractAddress);
        require(checkSignatures(keccak256(abi.encodePacked(thisContractAddress, newContractAddress, salt, erc20nativeTokens, _networkId)),
            v,
            r,
            s), "Peer signatures are invalid"
        );
        for (uint i = 0; i < _sidechainTokenAddressArray.length; i++) {
            Ownable token = Ownable(_sidechainTokenAddressArray[i]);
            token.transferOwnership(newContractAddress);
        }
        for (uint i = 0; i < erc20nativeTokens.length; i++) {
            IERC20 token = IERC20(erc20nativeTokens[i]);
            token.transfer(newContractAddress, token.balanceOf(address(this)));
        }
        Bridge(newContractAddress).receivePayment{value: address(this).balance}();
        initialized_ = false;
        emit Migrated(newContractAddress);
    }


    function addNewSidechainToken(
        string memory name,
        string memory symbol,
        uint8 decimals,
        bytes32 sidechainAssetId,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s)
    public shouldBeInitialized {
        require(used[txHash] == false);
        require(checkSignatures(keccak256(abi.encodePacked(
                name,
                symbol,
                decimals,
                sidechainAssetId,
                txHash,
                _networkId
            )),
            v,
            r,
            s), "Peer signatures are invalid"
        );

        MasterToken tokenInstance = new MasterToken(name, symbol, decimals, address(this), 0, sidechainAssetId);
        address tokenAddress = address(tokenInstance);
        _sidechainTokens[sidechainAssetId] = tokenAddress;
        _sidechainTokensByAddress[tokenAddress] = sidechainAssetId;
        _sidechainTokenAddressArray.push(tokenAddress);
        used[txHash] = true;
    }


    function sendEthToSidechain(
        bytes32 to
    )
    public
    payable
    shouldBeInitialized shouldNotBePreparedForMigration {
        require(msg.value > 0, "ETH VALUE SHOULD BE MORE THAN 0");
        bytes32 empty;
        emit Deposit(to, msg.value, address(0x0), empty);
    }


    function sendERC20ToSidechain(
        bytes32 to,
        uint amount,
        address tokenAddress)
    external
    shouldBeInitialized shouldNotBePreparedForMigration {
        IERC20 token = IERC20(tokenAddress);

        require(token.allowance(msg.sender, address(this)) >= amount, "NOT ENOUGH DELEGATED TOKENS ON SENDER BALANCE");

        bytes32 sidechainAssetId = _sidechainTokensByAddress[tokenAddress];
        if (sidechainAssetId != "" || _addressVAL == tokenAddress || _addressXOR == tokenAddress) {
            ERC20Burnable mtoken = ERC20Burnable(tokenAddress);
            mtoken.burnFrom(msg.sender, amount);
        } else {
            require(acceptedEthTokens[tokenAddress], "The Token is not accepted for transfer to sidechain");
            token.transferFrom(msg.sender, address(this), amount);
        }
        emit Deposit(to, amount, tokenAddress, sidechainAssetId);
    }


    function addPeerByPeer(
        address newPeerAddress,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public
    shouldBeInitialized
    returns (bool)
    {
        require(used[txHash] == false);
        require(checkSignatures(keccak256(abi.encodePacked(newPeerAddress, txHash, _networkId)),
            v,
            r,
            s), "Peer signatures are invalid"
        );

        addPeer(newPeerAddress);
        used[txHash] = true;
        emit ChangePeers(newPeerAddress, false);
        return true;
    }


    function removePeerByPeer(
        address peerAddress,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public
    shouldBeInitialized
    returns (bool)
    {
        require(used[txHash] == false);
        require(checkSignatures(
                keccak256(abi.encodePacked(peerAddress, txHash, _networkId)),
                v,
                r,
                s), "Peer signatures are invalid"
        );

        removePeer(peerAddress);
        used[txHash] = true;
        emit ChangePeers(peerAddress, true);
        return true;
    }


    function receiveByEthereumAssetAddress(
        address tokenAddress,
