        _sidechainTokens[sidechainAssetId] = tokenAddress;
        _sidechainTokensByAddress[tokenAddress] = sidechainAssetId;
        _sidechainTokenAddressArray.push(tokenAddress);
        used[txHash] = true;
    }


    function sendEthToSidechain(
        bytes32 to
    )
    public
    payable
    shouldBeInitialized shouldNotBePreparedForMigration {
        require(msg.value > 0, "ETH VALUE SHOULD BE MORE THAN 0");
        bytes32 empty;
        emit Deposit(to, msg.value, address(0x0), empty);
    }


    function sendERC20ToSidechain(
        bytes32 to,
        uint amount,
        address tokenAddress)
    external
    shouldBeInitialized shouldNotBePreparedForMigration {
        IERC20 token = IERC20(tokenAddress);

        require(token.allowance(msg.sender, address(this)) >= amount, "NOT ENOUGH DELEGATED TOKENS ON SENDER BALANCE");

        bytes32 sidechainAssetId = _sidechainTokensByAddress[tokenAddress];
        if (sidechainAssetId != "" || _addressVAL == tokenAddress || _addressXOR == tokenAddress) {
            ERC20Burnable mtoken = ERC20Burnable(tokenAddress);
            mtoken.burnFrom(msg.sender, amount);
        } else {
            require(acceptedEthTokens[tokenAddress], "The Token is not accepted for transfer to sidechain");
            token.transferFrom(msg.sender, address(this), amount);
        }
        emit Deposit(to, amount, tokenAddress, sidechainAssetId);
    }


    function addPeerByPeer(
        address newPeerAddress,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public
    shouldBeInitialized
    returns (bool)
    {
        require(used[txHash] == false);
        require(checkSignatures(keccak256(abi.encodePacked(newPeerAddress, txHash, _networkId)),
            v,
            r,
            s), "Peer signatures are invalid"
        );

        addPeer(newPeerAddress);
        used[txHash] = true;
        emit ChangePeers(newPeerAddress, false);
        return true;
    }


    function removePeerByPeer(
        address peerAddress,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public
    shouldBeInitialized
    returns (bool)
    {
        require(used[txHash] == false);
        require(checkSignatures(
                keccak256(abi.encodePacked(peerAddress, txHash, _networkId)),
                v,
                r,
                s), "Peer signatures are invalid"
        );

        removePeer(peerAddress);
        used[txHash] = true;
        emit ChangePeers(peerAddress, true);
        return true;
    }


    function receiveByEthereumAssetAddress(
        address tokenAddress,
        uint256 amount,
        address payable to,
        address from,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public shouldBeInitialized
    {
        require(used[txHash] == false);
        require(checkSignatures(
                keccak256(abi.encodePacked(tokenAddress, amount, to, from, txHash, _networkId)),
                v,
                r,
                s), "Peer signatures are invalid"
        );

        if (tokenAddress == address(0)) {
            used[txHash] = true;

            to.transfer(amount);
        } else {
            IERC20 coin = IERC20(tokenAddress);
            used[txHash] = true;

            coin.transfer(to, amount);
        }
        emit Withdrawal(txHash);
    }


    function receiveBySidechainAssetId(
        bytes32 sidechainAssetId,
        uint256 amount,
        address to,
        address from,
        bytes32 txHash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    public shouldBeInitialized
    {
        require(_sidechainTokens[sidechainAssetId] != address(0x0), "Sidechain asset is not registered");
        require(used[txHash] == false);
        require(checkSignatures(
                keccak256(abi.encodePacked(sidechainAssetId, amount, to, from, txHash, _networkId)),
                v,
                r,
                s), "Peer signatures are invalid"
        );

        MasterToken tokenInstance = MasterToken(_sidechainTokens[sidechainAssetId]);
        tokenInstance.mintTokens(to, amount);
        used[txHash] = true;
        emit Withdrawal(txHash);
    }


    function checkSignatures(bytes32 hash,
        uint8[] memory v,
        bytes32[] memory r,
        bytes32[] memory s
    )
    private
    returns (bool) {
        require(peersCount >= 1);
        require(v.length == r.length);
        require(r.length == s.length);
        uint needSigs = peersCount - (peersCount - 1) / 3;
        require(s.length >= needSigs);

        uint count = 0;
        address[] memory recoveredAddresses = new address[](s.length);
        for (uint i = 0; i < s.length; ++i) {
            address recoveredAddress = recoverAddress(
                hash,
                v[i],
                r[i],
                s[i]
            );


            if (isPeer[recoveredAddress] != true || _uniqueAddresses[recoveredAddress] == true) {
                continue;
            }
            recoveredAddresses[count] = recoveredAddress;
            count = count + 1;
            _uniqueAddresses[recoveredAddress] = true;
        }


        for (uint i = 0; i < count; ++i) {
            _uniqueAddresses[recoveredAddresses[i]] = false;
        }

        return count >= needSigs;
    }


    function recoverAddress(
        bytes32 hash,
        uint8 v,
        bytes32 r,
        bytes32 s)
    private
    pure
    returns (address) {
        bytes32 simple_hash = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", hash));
        address res = ecrecover(simple_hash, v, r, s);
        return res;
    }


    function addPeer(address newAddress)
    internal
    returns (uint) {
        require(isPeer[newAddress] == false);
        isPeer[newAddress] = true;
        ++peersCount;
        return peersCount;
    }

    function removePeer(address peerAddress)
    internal {
        require(isPeer[peerAddress] == true);
        isPeer[peerAddress] = false;
        --peersCount;
    }
}

pragma solidity ^0.8.9;

import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract CheckDotPrivateSale {
    using SafeMath for uint256;

    address private                         _owner;
    address private                         _cdtTokenAddress;
    mapping(address => uint256) private     _wallets_investment;

    uint256 public                          _ethSolded;
    uint256 public                          _cdtSolded;
    uint256 public                          _cdtPereth;
    uint256 public                          _maxethPerWallet;
    bool public                             _paused = false;
    bool public                             _claim = false;

    event NewAmountPresale(uint256 srcAmount, uint256 cdtPereth, uint256 totalCdt);
    event StateChange();


    constructor(address checkDotTokenAddr, uint256 cdtPereth, uint256 maxethPerWallet) {
        require(msg.sender != address(0), "Deploy from the zero address");
        _owner = msg.sender;
        _ethSolded = 0;
        _cdtPereth = cdtPereth;
        _cdtTokenAddress = checkDotTokenAddr;
        _maxethPerWallet = maxethPerWallet;
    }


    modifier onlyOwner() {
        require(msg.sender == _owner, "Only the owner can do this action");
        _;
    }


    receive() external payable {
        require(_paused == false, "Presale is paused");
        uint256 totalInvested = _wallets_investment[address(msg.sender)].add(msg.value);
        require(totalInvested <= _maxethPerWallet, "You depassed the limit of max eth per wallet for the presale.");
        _transfertCDT(msg.value);
    }


    function setPaused(bool value) public payable onlyOwner {
        _paused = value;
        emit StateChange();
    }


    function setClaim(bool value) public payable onlyOwner {
        _claim = value;
        emit StateChange();
    }


    function claimCdt() public
    {
        IERC20 cdtToken = IERC20(_cdtTokenAddress);

        require(_claim == true, "You cant claim your CDT yet");
        uint256 srcAmount =  _wallets_investment[address(msg.sender)];
        require(srcAmount > 0, "You dont have any CDT to claim");

        uint256 cdtAmount = (srcAmount.mul(_cdtPereth)).div(10 ** 18);
         require(
            cdtToken.balanceOf(address(this)) >= cdtAmount,
            "No CDT amount required on the contract"
        );
        _wallets_investment[address(msg.sender)] = 0;
        cdtToken.transfer(msg.sender, cdtAmount);
    }


    function getMaxEthPerWallet() public view returns(uint256) {
        return _maxethPerWallet;
    }


    function getCdtPerEth() public view returns(uint256) {
        return _cdtPereth;
    }


    function getTotalRaisedEth() public view returns(uint256) {
        return _ethSolded;
    }


    function getTotalRaisedCdt() public view returns(uint256) {
        return _cdtSolded;
    }


    function getAddressInvestment(address addr) public view returns(uint256) {
        return  _wallets_investment[addr];
    }


    function _transfertCDT(uint256 _srcAmount) private {
        IERC20 cdtToken = IERC20(_cdtTokenAddress);
        uint256 cdtAmount = (_srcAmount.mul(_cdtPereth)).div(10 ** 18);

        emit NewAmountPresale(_srcAmount, _cdtPereth, cdtAmount);

        require(
            cdtToken.balanceOf(address(this)) >= cdtAmount.add(_cdtSolded),
            "No CDT amount required on the contract"
        );

        _ethSolded += _srcAmount;
        _cdtSolded += cdtAmount;
        _wallets_investment[msg.sender] += _srcAmount;
    }


    function withdraw() public payable onlyOwner {
        payable(msg.sender).transfer(address(this).balance);
    }


    function withdrawRemainingCDT() public payable onlyOwner {
        IERC20 cdtToken = IERC20(_cdtTokenAddress);

        cdtToken.transfer(msg.sender, cdtToken.balanceOf(address(this)));
    }
}

