    }

    function changeTimeLockWithdraw(uint256 _timeLock) public {
        require(hasRole(DEFAULT_ADMIN_ROLE, address(msg.sender)), "Caller is not a owner");
        timeLockWithdraw = _timeLock;
    }
    function changeTimeLockClaim(uint256 _timeLock) public {
        require(hasRole(DEFAULT_ADMIN_ROLE, address(msg.sender)), "Caller is not a owner");
        timeLockClaim = _timeLock;
    }
    function changeHePerBlock(uint256 _hePerBlock) public {
        require(hasRole(DEFAULT_ADMIN_ROLE, address(msg.sender)), "Caller is not a owner");
        massUpdatePools();
        HePerBlock = _hePerBlock;
    }
    function getWithdrawByAddress(uint256 _pid, address _address) public view returns (WithdrawInfo[]  memory) {
        return withdrawInfo[_pid][_address];
    }
    function getClaimByAddress(uint256 _pid, address _address) public view returns (ClaimInfo[]  memory) {
        return claimInfo[_pid][_address];
    }
    function add(uint256 _allocPoint, IBEP20 _heToken, bool _withUpdate) public {
        require(hasRole(DEFAULT_ADMIN_ROLE, address(msg.sender)), "Caller is not a owner");
        require(block.number > startBlock, 'has not started yet');
        if (_withUpdate) {
            massUpdatePools();
        }
        uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        poolInfo.push(PoolInfo({
            heToken: _heToken,
            allocPoint: _allocPoint,
            lastRewardBlock: lastRewardBlock,
            accHePerShare: 0,
            balancePool: 0
        }));
    }
    function set(uint256 _pid, uint256 _allocPoint, bool _withUpdate) public {
        require(hasRole(DEFAULT_ADMIN_ROLE, address(msg.sender)), "Caller is not a owner");
        if (_withUpdate) {
            massUpdatePools();
        }
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(_allocPoint);
        poolInfo[_pid].allocPoint = _allocPoint;
    }
    function addViewWallet(uint256 _pid, address _receive) public{
        require(!boolAddWallet[_pid][_receive], "Wallet has been added");
        addressStake[_pid][address(_receive)] = msg.sender;
        boolAddWallet[_pid][_receive] = true;
        emit AddWallet(msg.sender, _pid, address(_receive), block.timestamp);
    }
    function getViewWallet(uint256 _pid, address _receive) public view returns (uint256){
        address staker = addressStake[_pid][_receive];
        UserInfo storage user = userInfo[_pid][staker];
        uint256 amount = user.amount;
        return amount;
    }

    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {
        if (_to <= bonusEndBlock) {
            return _to.sub(_from).mul(BONUS_MULTIPLIER);
        } else if (_from >= bonusEndBlock) {
            return _to.sub(_from);
        } else {
            return bonusEndBlock.sub(_from).mul(BONUS_MULTIPLIER).add(
                _to.sub(bonusEndBlock)
            );
        }
    }

    function getRewardPerBlock(uint blockNumber) public view returns (uint256) {
        if (blockNumber >= startBlock){
            return HePerBlock;
        } else {
            return 0;
        }
    }

    function pendingToken(uint256 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accHePerShare = pool.accHePerShare;
        uint256 lpSupply = pool.balancePool;
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 rewardThisBlock = getRewardPerBlock(block.number);
            uint256 heReward = multiplier.mul(rewardThisBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accHePerShare = accHePerShare.add(heReward.mul(1e18).div(lpSupply));
        }
        uint256 rewardHe = user.amount.mul(accHePerShare).div(1e18).sub(user.rewardDebt).add(user.pendingDebt);
        return rewardHe;
    }

    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return; 
        }
        uint256 lpSupply = pool.balancePool;
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 rewardThisBlock = getRewardPerBlock(block.number);
        uint256 heReward = multiplier.mul(rewardThisBlock).mul(pool.allocPoint).div(totalAllocPoint);
        pool.accHePerShare = pool.accHePerShare.add(heReward.mul(1e18).div(lpSupply));
        pool.lastRewardBlock = block.number;
    }

    function deposit(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        updatePool(_pid);
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accHePerShare).div(1e18).sub(user.rewardDebt);
            if(pending > 0){
                user.pendingDebt = user.pendingDebt.add(pending);


            }
        } 
        if(_amount > 0){
            pool.heToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            pool.balancePool = pool.balancePool.add(_amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accHePerShare).div(1e18);
        emit Deposit(msg.sender, _pid, _amount, block.timestamp);
    }


    function pendingWithdraw(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(_pid);
        uint256 pending = user.amount.mul(pool.accHePerShare).div(1e18).sub(user.rewardDebt);

        user.amount = user.amount.sub(_amount);
        user.rewardDebt = user.amount.mul(pool.accHePerShare).div(1e18);
        pool.balancePool = pool.balancePool.sub(_amount);
        withdrawInfo[_pid][msg.sender].push(WithdrawInfo(_amount, block.timestamp, 0)); 
        user.pendingDebt = user.pendingDebt.add(pending);



    }

    function withdraw(uint256 _pid, uint256 _id) public {
        PoolInfo storage pool = poolInfo[_pid];
        uint256 status = withdrawInfo[_pid][msg.sender][_id].status;
        uint256 amount = withdrawInfo[_pid][msg.sender][_id].amount;
        uint256 timeWithdraw = withdrawInfo[_pid][msg.sender][_id].blockTime;
        require(status == 0, 'You have withdrawn');

        require(amount >= 0 , 'withdraw: not good'); 
        require((block.timestamp - timeWithdraw) > timeLockWithdraw, 'you are still in lock');
        withdrawInfo[_pid][msg.sender][_id].status = 1;
        pool.heToken.safeTransfer(address(msg.sender), amount);
        emit Withdraw(msg.sender, _pid, amount, block.timestamp);
    }
    function pendingClaim(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= 0, "withdraw: not good");
        updatePool(_pid);
        uint256 pending = user.amount.mul(pool.accHePerShare).div(1e18).sub(user.rewardDebt);
        user.rewardDebt = user.amount.mul(pool.accHePerShare).div(1e18);
        require(user.pendingDebt.add(pending) >= _amount, "Claim: not good");
        user.pendingDebt = user.pendingDebt.add(pending).sub(_amount);
        claimInfo[_pid][msg.sender].push(ClaimInfo(_amount, block.timestamp, 0)); 

    }
    function claim(uint256 _pid, uint256 _id) public {
        uint256 status = claimInfo[_pid][msg.sender][_id].status;
        uint256 amount = claimInfo[_pid][msg.sender][_id].amount;
        uint256 timeWithdraw = claimInfo[_pid][msg.sender][_id].blockTime;
        require(status == 0, 'You have withdrawn');
        require(amount >= 0 , 'withdraw: not good');
        require((block.timestamp - timeWithdraw) > timeLockClaim, 'you are still in lock');
        claimInfo[_pid][msg.sender][_id].status = 1;

        RE.transferToken(HE,address(msg.sender), amount);
        emit Claim(msg.sender, _pid, amount, block.timestamp);
    }
    function reInvestment(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= 0, "amount: not good");
        require(pool.heToken == HE, "Token does not support restake");
        updatePool(_pid);
        uint256 pending = user.amount.mul(pool.accHePerShare).div(1e18).sub(user.rewardDebt);
        require(user.pendingDebt.add(pending) >= _amount, "Claim: not good");
        user.pendingDebt = user.pendingDebt.add(pending).sub(_amount);
        pool.balancePool = pool.balancePool.add(_amount);
        user.amount = user.amount.add(_amount);
        user.rewardDebt = user.amount.mul(pool.accHePerShare).div(1e18);
        RE.transferToken(HE,address(this), _amount);
        emit ReInvestment(msg.sender, _pid, _amount, block.timestamp);

    }

    function emergencyWithdraw(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        withdrawInfo[_pid][msg.sender].push(WithdrawInfo(user.amount, block.timestamp, 0));
        pool.balancePool = pool.balancePool.sub(user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount, block.timestamp);
        user.amount = 0;
        user.rewardDebt = 0;
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract LockletPrivateSale is Ownable, Pausable {
    using SafeMath for uint256;

    ERC20 private _lktToken;
    mapping(address => uint256) private _investments;

    uint256 public _raisedEth;
    uint256 public _soldedLkt;

    uint256 public _lktPerEth;
    uint256 public _maxEthPerAddr;

    bool private _claimable = false;

    event NewAllowance(uint256 ethCostAmount, uint256 lktPerEth, uint256 lktAllocatedAmount);

    constructor(
        address lktTokenAddr,
        uint256 lktPerEth,
        uint256 maxEthPerAddr
    ) {
        _lktToken = ERC20(lktTokenAddr);
        _lktPerEth = lktPerEth;
        _maxEthPerAddr = maxEthPerAddr;

        _raisedEth = 0;
        _soldedLkt = 0;

        _pause();
    }



    receive() external payable whenNotPaused {
        uint256 totalEthInvested = _investments[msg.sender].add(msg.value);
        require(totalEthInvested <= _maxEthPerAddr, "LockletPrivateSale: You exceed the Ether limit per wallet");
        _allocateLkt(msg.value);
    }

    function claim() external {
        require(_claimable == true, "LockletPrivateSale: Claim is not activated");

        uint256 lktAmount = getAllowanceByAddr(msg.sender);
        require(lktAmount > 0, "LockletPrivateSale: Nothing to claim");

        require(_lktToken.balanceOf(address(this)) >= lktAmount, "LockletPrivateSale: Not enough LKT available");

        _investments[msg.sender] = 0;
        _lktToken.transfer(msg.sender, lktAmount);
    }





    function _allocateLkt(uint256 ethAmount) private {
        uint256 lktAmount = (ethAmount.mul(_lktPerEth)).div(10**18);
        require(_lktToken.balanceOf(address(this)) >= lktAmount.add(_soldedLkt), "LockletPrivateSale: Not enough LKT available");

        _raisedEth += ethAmount;
        _soldedLkt += lktAmount;
        _investments[msg.sender] += ethAmount;

        emit NewAllowance(ethAmount, _lktPerEth, lktAmount);
    }





    function pause() public onlyOwner {
        _pause();
    }

    function unpause() public onlyOwner {
        _unpause();
    }

    function setLktPerEth(uint256 lktPerEth) public onlyOwner {
        _lktPerEth = lktPerEth;
    }

    function setMaxEthPerAddr(uint256 maxEthPerAddr) public onlyOwner {
        _maxEthPerAddr = maxEthPerAddr;
    }

    function setClaimable(bool value) public onlyOwner {
        _claimable = value;
    }

    function withdrawEth() public onlyOwner {
        payable(msg.sender).transfer(address(this).balance);
    }

    function withdrawLkt() public onlyOwner {
        _lktToken.transfer(msg.sender, _lktToken.balanceOf(address(this)));
    }





    function getRaisedEth() public view returns (uint256) {
        return _raisedEth;
    }

    function getSoldedLkt() public view returns (uint256) {
        return _soldedLkt;
    }

    function getLktPerEth() public view returns (uint256) {
        return _lktPerEth;
    }

    function getMaxEthPerAddr() public view returns (uint256) {
        return _maxEthPerAddr;
    }

    function getAllowanceByAddr(address addr) public view returns (uint256) {
        uint256 totalEthInvested = _investments[addr];
        uint256 lktAmount = (totalEthInvested.mul(_lktPerEth)).div(10**18);
        return lktAmount;
    }

    function getClaimable() public view returns (bool) {
        return _claimable;
    }


}

